// Get tenant from Lookup Tenant
const tenant = $('Lookup Tenant').item.json;

// Get normalized message data - try each channel's normalize node
let normalized = {};
try { normalized = $('Normalize Telegram').item.json; } catch(e) {
  try { normalized = $('Normalize Email').item.json; } catch(e2) {
    try { normalized = $('Normalize SMS').item.json; } catch(e3) {
      try { normalized = $('Normalize WhatsApp').item.json; } catch(e4) {
        normalized = {};
      }
    }
  }
}

return {
  json: {
    tenant_id: tenant.id || '',
    tenant_name: tenant.name || tenant.tenant_name || '',
    phone: tenant.phone || '',
    unit: tenant.unit_number || '',
    property: tenant.property || '',
    email: tenant.email || '',
    telegram_id: tenant.telegram_id || '',
    language_pref: tenant.language_pref || 'fr',
    channel: normalized.channel || '',
    message: normalized.message || '',
    subject: normalized.subject || '',
    chat_id: normalized.chat_id || tenant.telegram_id || '',
    sender_identifier: normalized.sender_identifier || '',
    has_media: normalized.has_media || false,
    media_type: normalized.media_type || '',
    media_id: normalized.media_id || '',
    external_message_id: normalized.external_message_id || '',
    message_db_id: $('Log Inbound Message').item.json.id || ''
  }
};

// Get normalized data from whichever normalize node ran
let normalized = {};
try { normalized = $('Normalize Telegram').item.json; } catch(e) {
  try { normalized = $('Normalize Email').item.json; } catch(e2) {
    try { normalized = $('Normalize SMS').item.json; } catch(e3) {
      try { normalized = $('Normalize WhatsApp').item.json; } catch(e4) {
        normalized = {};
      }
    }
  }
}

// Don't reply to unknown email senders (could be spam/newsletters)
if (normalized.channel === 'email') {
  return [];
}

return {
  json: {
    channel: normalized.channel || '',
    chat_id: normalized.chat_id || '',
    sender_identifier: normalized.sender_identifier || '',
    phone: normalized.sender_identifier || '',
    email: normalized.sender_identifier || '',
    response_text: "Bonjour, nous n'avons pas pu identifier votre compte locataire. Veuillez contacter Julia Inc au 438-900-9998.\n\nHello, we couldn't identify your tenant account. Please contact Julia Inc at 438-900-9998."
  }
};

const data = $('Telegram Trigger').item.json.callback_query.data;
const parts = data.split('||');
return {
  json: {
    action: parts[0],
    ticket_id: parts[1] || '',
    category: parts[2] || '',
    vendor_index: parts[3] || '0',
    chat_id: String($('Telegram Trigger').item.json.callback_query.message.chat.id)
  }
};

