const vendors = $('Lookup Vendor').all().map(v => v.json);
const aiMsg = $('AI Vendor Msg').item.json.text || $('AI Vendor Msg').item.json.response || '';
const ticketId = $('Parse Callback').item.json.ticket_id;
const category = $('Parse Callback').item.json.category;
const cbData = $('Parse Callback').item.json;

// Get vendor index from callback data (default 0)
const vendorIndex = parseInt(cbData.vendor_index || '0');
const vendor = vendors[vendorIndex] || vendors[0] || {};
const totalVendors = vendors.filter(v => v.vendor_name).length;

const preview = aiMsg.replace(/\n/g, ' ').substring(0, 400);

let text = 'DISPATCH PREVIEW (' + (vendorIndex + 1) + '/' + totalVendors + ')\n\n' +
  'Vendor: ' + (vendor.vendor_name || 'No vendor found') + '\n' +
  'Email: ' + (vendor.email || 'N/A') + '\n' +
  'Phone: ' + (vendor.phone || 'N/A') + '\n\n' +
  'Message preview:\n' + preview + '\n\n' +
  'Confirm dispatch to this vendor?';

return {
  json: {
    chat_id: '6216258938',
    text: text,
    ticket_id: ticketId,
    category: category,
    vendor_index: vendorIndex,
    total_vendors: totalVendors,
    vendor_email: vendor.email || '',
    vendor_name: vendor.vendor_name || ''
  }
};

const contractors = $('Get Contractors').all().map(c => c.json);
const category = $('Parse Callback').item.json.category;
const ticketId = $('Parse Callback').item.json.ticket_id;
let text = 'CONTRACTORS FOR ' + category.toUpperCase() + '\nTicket: ' + ticketId + '\n\n';
if (!contractors.length || !contractors[0].vendor_name) {
  text += 'No contractors found for this category.';
} else {
  contractors.forEach((c, i) => {
    text += (i+1) + '. ' + (c.vendor_name||'Unknown') + '\n   Phone: ' + (c.phone||'N/A') + '\n   Email: ' + (c.email||'N/A') + '\n\n';
  });
}
return { json: { text } };

