const data = $json;
const buttons = [];

// Always show Confirm
buttons.push({text: "Confirm Dispatch", callback_data: "confirm_dispatch||" + data.ticket_id + "||" + data.category + "||" + data.vendor_index});

// Show Next if more vendors available
if (data.vendor_index + 1 < data.total_vendors) {
  buttons.push({text: "Next >>", callback_data: "dispatch||" + data.ticket_id + "||" + data.category + "||" + (data.vendor_index + 1)});
}

// Always show "Show All" as fallback
buttons.push({text: "Show All", callback_data: "manual||" + data.ticket_id + "||" + data.category});

return {
  json: {
    method: 'POST',
    url: 'https://api.telegram.org/bot8460031715:AAE1IQYICVYo3BfDcOjY4IKYVu0iI4V9lZ8/sendMessage',
    body: {
      chat_id: '6216258938',
      text: data.text,
      reply_markup: { inline_keyboard: [buttons] }
    }
  }
};

// Merge normalized message data with tenant data
let normalized = {};
try { normalized = $('Normalize Telegram').item.json; } catch(e) {
  try { normalized = $('Normalize Email').item.json; } catch(e2) {
    try { normalized = $('Normalize SMS').item.json; } catch(e3) {
      try { normalized = $('Normalize WhatsApp').item.json; } catch(e4) {
        normalized = {};
      }
    }
  }
}

const tenant = $('Lookup Tenant').item.json;

return [{
  json: {
    ...tenant,
    norm_chat_id: normalized.chat_id || tenant.telegram_id || '',
    norm_message: normalized.message || '',
    norm_channel: normalized.channel || '',
    norm_ext_id: normalized.external_message_id || '',
    norm_subject: normalized.subject || '',
    norm_sender_identifier: normalized.sender_identifier || '',
    norm_has_media: normalized.has_media || false,
    norm_media_type: normalized.media_type || '',
  }
}];

// Extract message from Meta WhatsApp webhook payload
const body = $input.first().json.body || $input.first().json;

// Skip status updates (delivery receipts) - they don't have messages
if (body.entry?.[0]?.changes?.[0]?.value?.statuses) {
  return [];
}

const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const message = value?.messages?.[0];

if (!message || !message.from) {
  return [];
}

return [{
  json: {
    from: message.from,
    message_id: message.id || '',
    text: message.text?.body || message.caption || '',
    type: message.type || 'text',
    has_image: !!message.image,
    has_video: !!message.video,
    contact_name: value?.contacts?.[0]?.profile?.name || '',
  }
}];
